const listUsageLimits = `-- name: ListUsageLimits :many

SELECT uuid, policy_set_name, limit_type, limit_value, reset_period, is_enabled, created_at, updated_at FROM usage_limit
ORDER BY policy_set_name, limit_type
`

// ============================================================================
// Usage Limit Queries (Policy Set Defaults)
// ============================================================================
func (q *Queries) ListUsageLimits(ctx context.Context) ([]UsageLimit, error) {
	rows, err := q.db.Query(ctx, listUsageLimits)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []UsageLimit
	for rows.Next() {
		var i UsageLimit
		if err := rows.Scan(
			&i.UUID,
			&i.PolicySetName,
			&i.LimitType,
			&i.LimitValue,
			&i.ResetPeriod,
			&i.IsEnabled,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

